     1→/**
     2→ * AI Provider Fallback Service
     3→ *
     4→ * Provides automatic failover between AI providers per modality.
     5→ * When a provider fails (401, 402, 429, timeout), automatically
     6→ * switches to the next provider in the chain. No manual intervention.
     7→ *
     8→ * Modalities: LLM, TTS, ASR, Vision, Embedding
     9→ * Providers: Polsia/Anthropic, Polsia/OpenAI, NVIDIA NIM (multiple models)
    10→ */
    11→
    12→const OpenAI = require('openai');
    13→const Anthropic = require('@anthropic-ai/sdk');
    14→const fetch = require('node-fetch');
    15→const FormData = require('form-data');
    16→
    17→// Circuit breaker: skip providers that failed recently
    18→const CIRCUIT_BREAK_MS = 5 * 60 * 1000; // 5 minutes
    19→
    20→// HTTP status codes that indicate provider-level issues (retryable)
    21→const RETRYABLE_STATUS = new Set([401, 402, 429, 500, 502, 503, 504]);
    22→
    23→// NIM model defaults (overridable via env)
    24→const NIM_MODELS = {
    25→  llm_primary: process.env.NIM_LLM_MODEL || 'nvidia/llama-3.3-nemotron-super-49b-v1',
    26→  llm_secondary: process.env.NIM_LLM_FALLBACK_MODEL || 'deepseek-ai/deepseek-v3p2',
    27→  llm_tertiary: process.env.NIM_LLM_TERTIARY_MODEL || 'moonshot-ai/kimi-k2.5',
    28→  vision_primary: process.env.NIM_VISION_MODEL || 'nvidia/cosmos-reason2-8b',
    29→  vision_secondary: process.env.NIM_VISION_FALLBACK_MODEL || 'nvidia/nemotron-nano-12b-v2-vl',
    30→  asr: process.env.NIM_ASR_MODEL || 'nvidia/parakeet-tdt-0.6b-v2',
    31→  embedding: process.env.NIM_EMBED_MODEL || 'nvidia/llama-3.2-nv-embedqa-1b-v2',
    32→};
    33→
    34→class AIProviderService {
    35→  constructor() {
    36→    this.failures = {};          // { 'provider:modality': { count, lastFailure, error, status } }
    37→    this.activeProviders = {};   // { modality: providerKey }
    38→    this.logs = [];              // Recent failover events (last 100)
    39→    this.stats = {               // Cumulative stats
    40→      totalCalls: 0,
    41→      totalFailovers: 0,
    42→      providerCalls: {},         // { providerKey: count }
    43→    };
    44→
    45→    // Initialize clients
    46→    this.clients = {};
    47→    this.nimAvailable = false;
    48→    this._initClients();
    49→
    50→    console.log('[ai-provider] Initialized. NIM available:', this.nimAvailable);
    51→    console.log('[ai-provider] Providers:', Object.keys(this.clients).join(', '));
    52→  }
    53→
    54→  _initClients() {
    55→    // Anthropic client (Polsia proxy) — primary for LLM text
    56→    if (process.env.POLSIA_API_URL && process.env.POLSIA_API_KEY) {
    57→      this.clients.anthropic = new Anthropic({
    58→        baseURL: process.env.POLSIA_API_URL,
    59→        apiKey: process.env.POLSIA_API_KEY,
    60→      });
    61→    }
    62→
    63→    // OpenAI client (Polsia proxy) — primary for vision, TTS, ASR
    64→    if (process.env.OPENAI_BASE_URL && process.env.OPENAI_API_KEY) {
    65→      this.clients.openai = new OpenAI({
    66→        baseURL: process.env.OPENAI_BASE_URL,
    67→        apiKey: process.env.OPENAI_API_KEY,
    68→      });
    69→      this.openaiBaseUrl = process.env.OPENAI_BASE_URL;
    70→      this.openaiApiKey = process.env.OPENAI_API_KEY;
    71→    }
    72→
    73→    // NVIDIA NIM client — fallback for all modalities
    74→    const nimKey = process.env.NVIDIA_NIM_API_KEY;
    75→    const nimBase = process.env.NIM_BASE_URL || 'https://integrate.api.nvidia.com/v1';
    76→    if (nimKey) {
    77→      this.clients.nim = new OpenAI({
    78→        baseURL: nimBase,
    79→        apiKey: nimKey,
    80→      });
    81→      this.nimBaseUrl = nimBase;
    82→      this.nimApiKey = nimKey;
    83→      this.nimAvailable = true;
    84→    }
    85→  }
    86→
    87→  // ─── Fallback Chain Definitions ───────────────────────────────
    88→
    89→  getChain(modality) {
    90→    const chains = {
    91→      llm: [
    92→        'anthropic',       // Polsia/Claude — current primary
    93→        'openai',          // Polsia/OpenAI GPT-4o-mini
    94→        'nim_nemotron',    // NIM Nemotron Super 49B
    95→        'nim_kimi',        // NIM Kimi K2.5
    96→        'nim_deepseek',    // NIM DeepSeek V3.2
    97→      ],
    98→      vision: [
    99→        'openai_vision',   // Polsia/OpenAI GPT-4o
   100→        'nim_cosmos',      // NIM Cosmos Reason2 8B
   101→        'nim_nemotron_vl', // NIM Nemotron Nano 12B VL
   102→      ],
   103→      tts: [
   104→        'openai_tts',      // Polsia/OpenAI TTS-1
   105→        // Browser Web Speech API handled at frontend level
   106→      ],
   107→      asr: [
   108→        'openai_whisper',  // Polsia/OpenAI Whisper
   109→        'nim_parakeet',    // NIM Parakeet TDT 0.6B v2
   110→      ],
   111→      embedding: [
   112→        'openai_embed',    // Polsia/OpenAI text-embedding-3-small
   113→        'nim_embed',       // NIM NV-EmbedQA 1B v2
   114→      ],
   115→    };
   116→    return chains[modality] || [];
   117→  }
   118→
   119→  // Check if a provider is available (has required client/keys)
   120→  isProviderAvailable(providerKey) {
   121→    switch (providerKey) {
   122→      case 'anthropic':
   123→        return !!this.clients.anthropic;
   124→      case 'openai':
   125→      case 'openai_vision':
   126→      case 'openai_tts':
   127→      case 'openai_whisper':
   128→      case 'openai_embed':
   129→        return !!this.clients.openai;
   130→      case 'nim_nemotron':
   131→      case 'nim_kimi':
   132→      case 'nim_deepseek':
   133→      case 'nim_cosmos':
   134→      case 'nim_nemotron_vl':
   135→      case 'nim_parakeet':
   136→      case 'nim_embed':
   137→        return this.nimAvailable;
   138→      default:
   139→        return false;
   140→    }
   141→  }
   142→
   143→  // ─── Circuit Breaker ──────────────────────────────────────────
   144→
   145→  isCircuitOpen(providerKey, modality) {
   146→    const key = `${providerKey}:${modality}`;
   147→    const failure = this.failures[key];
   148→    if (!failure) return false;
   149→
   150→    const elapsed = Date.now() - failure.lastFailure;
   151→    if (elapsed > CIRCUIT_BREAK_MS) {
   152→      // Circuit closed — enough time passed, allow retry
   153→      delete this.failures[key];
   154→      return false;
   155→    }
   156→    return true;
   157→  }
   158→
   159→  recordFailure(providerKey, modality, error) {
   160→    const key = `${providerKey}:${modality}`;
   161→    const existing = this.failures[key] || { count: 0 };
   162→    const status = error.status || error.statusCode || null;
   163→
   164→    this.failures[key] = {
   165→      count: existing.count + 1,
   166→      lastFailure: Date.now(),
   167→      error: error.message || String(error),
   168→      status,
   169→    };
   170→
   171→    this.stats.totalFailovers++;
   172→
   173→    const logEntry = {
   174→      timestamp: new Date().toISOString(),
   175→      event: 'provider_failure',
   176→      provider: providerKey,
   177→      modality,
   178→      error: error.message || String(error),
   179→      status,
   180→    };
   181→    this.logs.push(logEntry);
   182→    if (this.logs.length > 100) this.logs.shift();
   183→
   184→    console.log(`[ai-provider] ❌ ${providerKey} failed for ${modality}: [${status || 'ERR'}] ${error.message || error}`);
   185→  }
   186→
   187→  recordSuccess(providerKey, modality) {
   188→    this.activeProviders[modality] = providerKey;
   189→    const key = `${providerKey}:${modality}`;
   190→    delete this.failures[key];
   191→
   192→    this.stats.totalCalls++;
   193→    this.stats.providerCalls[providerKey] = (this.stats.providerCalls[providerKey] || 0) + 1;
   194→  }
   195→
   196→  isRetryable(err) {
   197→    // Network/timeout errors
   198→    if (err.code === 'ETIMEDOUT' || err.code === 'ECONNREFUSED' || err.code === 'ECONNRESET' || err.code === 'ENOTFOUND') return true;
   199→    if (err.message && (err.message.includes('timeout') || err.message.includes('ETIMEDOUT'))) return true;
   200→
   201→    // HTTP status codes
   202→    const status = err.status || err.statusCode || (err.response && err.response.status);
   203→    if (status && RETRYABLE_STATUS.has(status)) return true;
   204→
   205→    // OpenAI SDK-specific error types
   206→    if (err.type === 'insufficient_quota' || err.code === 'insufficient_quota') return true;
   207→    if (err.type === 'rate_limit_exceeded' || err.code === 'rate_limit_exceeded') return true;
   208→
   209→    // Anthropic-specific
   210→    if (err.error && err.error.type === 'overloaded_error') return true;
   211→
   212→    return false;
   213→  }
   214→
   215→  // Get available providers for a modality (skipping unavailable + circuit-broken)
   216→  getAvailableChain(modality) {
   217→    return this.getChain(modality).filter(key =>
   218→      this.isProviderAvailable(key) && !this.isCircuitOpen(key, modality)
   219→    );
   220→  }
   221→
   222→  // ─── Core Execution with Fallback ────────────────────────────
   223→
   224→  /**
   225→   * Execute an AI call with automatic fallback.
   226→   * @param {string} modality - 'llm', 'vision', 'tts', 'asr', 'embedding'
   227→   * @param {Function} executeFn - async (providerKey) => result
   228→   * @returns {*} Result from the first successful provider
   229→   */
   230→  async execute(modality, executeFn) {
   231→    const chain = this.getAvailableChain(modality);
   232→
   233→    if (chain.length === 0) {
   234→      const allChain = this.getChain(modality);
   235→      const reasons = allChain.map(k => {
   236→        if (!this.isProviderAvailable(k)) return `${k}: not configured`;
   237→        if (this.isCircuitOpen(k, modality)) return `${k}: circuit open`;
   238→        return `${k}: unknown`;
   239→      });
   240→      throw new Error(`No available providers for ${modality}. ${reasons.join(', ')}`);
   241→    }
   242→
   243→    let lastError;
   244→    for (const providerKey of chain) {
   245→      try {
   246→        const result = await executeFn(providerKey);
   247→        this.recordSuccess(providerKey, modality);
   248→        return result;
   249→      } catch (err) {
   250→        lastError = err;
   251→        if (this.isRetryable(err)) {
   252→          this.recordFailure(providerKey, modality, err);
   253→          continue; // try next provider
   254→        }
   255→        // Non-retryable error (e.g., bad request, invalid input) — don't try others
   256→        throw err;
   257→      }
   258→    }
   259→
   260→    // All providers exhausted
   261→    console.error(`[ai-provider] All ${modality} providers exhausted.`);
   262→    throw lastError || new Error(`All ${modality} providers failed`);
   263→  }
   264→
   265→  // ─── LLM Chat Completion ─────────────────────────────────────
   266→
   267→  /**
   268→   * Chat completion with automatic provider fallback.
   269→   * @param {Array} messages - Array of { role, content } messages
   270→   * @param {Object} options - { system, maxTokens, max_tokens, temperature, subscriptionId, response_format }
   271→   * @returns {string} The AI response text
   272→   */
   273→  async chatCompletion(messages, options = {}) {
   274→    return this.execute('llm', async (providerKey) => {
   275→      switch (providerKey) {
   276→        case 'anthropic':
   277→          return this._anthropicChat(messages, options);
   278→        case 'openai':
   279→          return this._openaiChat('gpt-4o-mini', messages, options, true);
   280→        case 'nim_nemotron':
   281→          return this._nimChat(NIM_MODELS.llm_primary, messages, options);
   282→        case 'nim_kimi':
   283→          return this._nimChat(NIM_MODELS.llm_tertiary, messages, options);
   284→        case 'nim_deepseek':
   285→          return this._nimChat(NIM_MODELS.llm_secondary, messages, options);
   286→        default:
   287→          throw new Error(`Unknown LLM provider: ${providerKey}`);
   288→      }
   289→    });
   290→  }
   291→
   292→  async _anthropicChat(messages, options) {
   293→    const systemMsgs = messages.filter(m => m.role === 'system');
   294→    const nonSystemMsgs = messages.filter(m => m.role !== 'system');
   295→
   296→    const systemPrompt = options.system || (systemMsgs.length > 0 ? systemMsgs[0].content : undefined);
   297→    const msgs = nonSystemMsgs.map(m => ({
   298→      role: m.role,
   299→      content: typeof m.content === 'string' ? m.content : String(m.content),
   300→    }));
   301→    if (msgs.length === 0) msgs.push({ role: 'user', content: 'Hello' });
   302→
   303→    const response = await this.clients.anthropic.messages.create({
   304→      max_tokens: options.maxTokens || options.max_tokens || 8192,
   305→      messages: msgs,
   306→      system: systemPrompt,
   307→    }, {
   308→      headers: options.subscriptionId ? { 'X-Subscription-ID': options.subscriptionId } : {},
   309→    });
   310→
   311→    return response.content[0].text;
   312→  }
   313→
   314→  async _openaiChat(model, messages, options, isPolsia = false) {
   315→    const client = this.clients.openai;
   316→    const msgs = [];
   317→
   318→    if (options.system) {
   319→      msgs.push({ role: 'system', content: options.system });
   320→    }
   321→    for (const m of messages) {
   322→      if (m.role === 'system' && options.system) continue; // already added
   323→      msgs.push({ role: m.role, content: typeof m.content === 'string' ? m.content : String(m.content) });
   324→    }
   325→    if (msgs.length === 0) msgs.push({ role: 'user', content: 'Hello' });
   326→
   327→    const params = {
   328→      model,
   329→      messages: msgs,
   330→      max_tokens: options.maxTokens || options.max_tokens || 8192,
   331→      temperature: options.temperature || 0.7,
   332→    };
   333→
   334→    // Polsia proxy requires task field
   335→    if (isPolsia) params.task = 'chat-fallback';
   336→    if (options.response_format) params.response_format = options.response_format;
   337→
   338→    const response = await client.chat.completions.create(params);
   339→    return response.choices[0].message.content;
   340→  }
   341→
   342→  async _nimChat(model, messages, options) {
   343→    const client = this.clients.nim;
   344→    const msgs = [];
   345→
   346→    if (options.system) {
   347→      msgs.push({ role: 'system', content: options.system });
   348→    }
   349→    for (const m of messages) {
   350→      if (m.role === 'system' && options.system) continue;
   351→      msgs.push({ role: m.role, content: typeof m.content === 'string' ? m.content : String(m.content) });
   352→    }
   353→    if (msgs.length === 0) msgs.push({ role: 'user', content: 'Hello' });
   354→
   355→    const params = {
   356→      model,
   357→      messages: msgs,
   358→      max_tokens: options.maxTokens || options.max_tokens || 8192,
   359→      temperature: options.temperature || 0.7,
   360→    };
   361→
   362→    if (options.response_format) params.response_format = options.response_format;
   363→
   364→    const response = await client.chat.completions.create(params);
   365→    return response.choices[0].message.content;
   366→  }
   367→
   368→  // ─── Vision Analysis ─────────────────────────────────────────
   369→
   370→  /**
   371→   * Vision analysis with automatic provider fallback.
   372→   * @param {Array} imageUrls - Array of HTTP image URLs
   373→   * @param {string} prompt - Analysis prompt
   374→   * @param {Object} options - { maxTokens, subscriptionId, response_format }
   375→   * @returns {string} The AI response text
   376→   */
   377→  async visionAnalysis(imageUrls, prompt, options = {}) {
   378→    return this.execute('vision', async (providerKey) => {
   379→      let client, model;
   380→
   381→      switch (providerKey) {
   382→        case 'openai_vision':
   383→          client = this.clients.openai;
   384→          model = 'gpt-4o';
   385→          break;
   386→        case 'nim_cosmos':
   387→          client = this.clients.nim;
   388→          model = NIM_MODELS.vision_primary;
   389→          break;
   390→        case 'nim_nemotron_vl':
   391→          client = this.clients.nim;
   392→          model = NIM_MODELS.vision_secondary;
   393→          break;
   394→        default:
   395→          throw new Error(`Unknown vision provider: ${providerKey}`);
   396→      }
   397→
   398→      // Build content array with text + images
   399→      const content = [{ type: 'text', text: prompt }];
   400→      for (const url of imageUrls) {
   401→        content.push({
   402→          type: 'image_url',
   403→          image_url: { url, detail: 'low' },
   404→        });
   405→      }
   406→
   407→      const params = {
   408→        model,
   409→        max_tokens: options.maxTokens || 2048,
   410→        messages: [
   411→          ...(options.system ? [{ role: 'system', content: options.system }] : []),
   412→          { role: 'user', content },
   413→        ],
   414→      };
   415→
   416→      // Polsia proxy needs task field
   417→      if (providerKey === 'openai_vision') params.task = options.task || 'vision-analysis';
   418→      if (options.response_format) params.response_format = options.response_format;
   419→
   420→      const response = await client.chat.completions.create(params);
   421→      return response.choices[0].message.content;
   422→    });
   423→  }
   424→
   425→  // ─── Text-to-Speech ──────────────────────────────────────────
   426→
   427→  /**
   428→   * Text-to-speech with automatic provider fallback.
   429→   * @param {string} text - Text to convert to speech
   430→   * @param {Object} options - { voice, speed, subscriptionId }
   431→   * @returns {Buffer|null} Audio buffer (MP3) or null if all providers fail
   432→   */
   433→  async textToSpeech(text, options = {}) {
   434→    try {
   435→      return await this.execute('tts', async (providerKey) => {
   436→        switch (providerKey) {
   437→          case 'openai_tts':
   438→            return this._openaiTTS(text, options);
   439→          default:
   440→            throw new Error(`Unknown TTS provider: ${providerKey}`);
   441→        }
   442→      });
   443→    } catch (err) {
   444→      // TTS has browser fallback — return null to signal frontend to use Web Speech API
   445→      console.error('[ai-provider] All TTS providers failed, frontend will use browser fallback:', err.message);
   446→      return null;
   447→    }
   448→  }
   449→
   450→  async _openaiTTS(text, options) {
   451→    const voice = options.voice || 'nova';
   452→    const speed = options.speed || 1.0;
   453→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
   454→
   455→    const baseUrl = this.openaiBaseUrl || 'https://api.openai.com/v1';
   456→    const apiKey = this.openaiApiKey;
   457→
   458→    const headers = {
   459→      'Authorization': `Bearer ${apiKey}`,
   460→      'Content-Type': 'application/json',
   461→    };
   462→    if (options.subscriptionId) headers['X-Subscription-ID'] = options.subscriptionId;
   463→
   464→    const res = await fetch(`${baseUrl}/audio/speech`, {
   465→      method: 'POST',
   466→      headers,
   467→      body: JSON.stringify({
   468→        model: 'tts-1',
   469→        input: truncatedText,
   470→        voice,
   471→        response_format: 'mp3',
   472→        speed,
   473→        task: 'tts-interview',
   474→      }),
   475→    });
   476→
   477→    if (!res.ok) {
   478→      const errText = await res.text();
   479→      const err = new Error(`TTS API error: ${res.status} ${errText.substring(0, 200)}`);
   480→      err.status = res.status;
   481→      throw err;
   482→    }
   483→
   484→    const arrayBuffer = await res.arrayBuffer();
   485→    return Buffer.from(arrayBuffer);
   486→  }
   487→
   488→  // ─── Speech-to-Text (ASR) ────────────────────────────────────
   489→
   490→  /**
   491→   * Transcribe audio with automatic provider fallback.
   492→   * @param {Buffer} audioBuffer - Audio data buffer
   493→   * @param {string} filename - Filename with extension
   494→   * @param {string} contentType - MIME type
   495→   * @param {Object} options - { subscriptionId }
   496→   * @returns {Object|null} Transcription result or null
   497→   */
   498→  async transcribeAudio(audioBuffer, filename, contentType, options = {}) {
   499→    try {
   500→      return await this.execute('asr', async (providerKey) => {
   501→        switch (providerKey) {
   502→          case 'openai_whisper':
   503→            return this._openaiWhisper(audioBuffer, filename, contentType, options);
   504→          case 'nim_parakeet':
   505→            return this._nimASR(audioBuffer, filename, contentType, options);
   506→          default:
   507→            throw new Error(`Unknown ASR provider: ${providerKey}`);
   508→        }
   509→      });
   510→    } catch (err) {
   511→      console.error('[ai-provider] All ASR providers failed:', err.message);
   512→      return null;
   513→    }
   514→  }
   515→
   516→  async _openaiWhisper(audioBuffer, filename, contentType, options) {
   517→    const formData = new FormData();
   518→    formData.append('file', audioBuffer, { filename, contentType });
   519→    formData.append('model', 'whisper-1');
   520→    formData.append('response_format', 'verbose_json');
   521→
   522→    const baseUrl = this.openaiBaseUrl || 'https://api.openai.com/v1';
   523→    const apiKey = this.openaiApiKey;
   524→
   525→    const headers = {
   526→      'Authorization': `Bearer ${apiKey}`,
   527→      ...formData.getHeaders(),
   528→    };
   529→    if (options.subscriptionId) headers['X-Subscription-ID'] = options.subscriptionId;
   530→
