   569→  const fillerCounts = {};
   570→  let totalFillers = 0;
   571→  const lowerTranscription = transcription.toLowerCase();
   572→
   573→  for (const filler of fillerWords) {
   574→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   575→    const matches = lowerTranscription.match(regex);
   576→    if (matches && matches.length > 0) {
   577→      fillerCounts[filler] = matches.length;
   578→      totalFillers += matches.length;
   579→    }
   580→  }
   581→
   582→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   583→
   584→  // Pace analysis
   585→  let paceAssessment = 'good';
   586→  let paceFeedback = '';
   587→  if (wpm < 100) {
   588→    paceAssessment = 'too_slow';
   589→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   590→  } else if (wpm < 120) {
   591→    paceAssessment = 'slightly_slow';
   592→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   593→  } else if (wpm <= 160) {
   594→    paceAssessment = 'good';
   595→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   596→  } else if (wpm <= 180) {
   597→    paceAssessment = 'slightly_fast';
   598→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   599→  } else {
   600→    paceAssessment = 'too_fast';
   601→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   602→  }
   603→
   604→  // Sentence structure analysis
   605→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   606→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   607→
   608→  // Communication score (1-10)
   609→  let communicationScore = 7;
   610→  // Penalize for filler words
   611→  if (fillerRate > 5) communicationScore -= 2;
   612→  else if (fillerRate > 3) communicationScore -= 1;
   613→  // Penalize for bad pace
   614→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   615→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   616→  // Reward for good sentence structure
   617→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   618→  // Penalize for very short responses
   619→  if (wordCount < 50) communicationScore -= 2;
   620→  else if (wordCount < 100) communicationScore -= 1;
   621→  // Reward for substantial responses
   622→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   623→
   624→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   625→
   626→  return {
   627→    word_count: wordCount,
   628→    duration_seconds: durationSeconds,
   629→    words_per_minute: wpm,
   630→    filler_words: fillerCounts,
   631→    total_fillers: totalFillers,
   632→    filler_rate: Math.round(fillerRate * 10) / 10,
   633→    pace: {
   634→      assessment: paceAssessment,
   635→      wpm,
   636→      feedback: paceFeedback
   637→    },
   638→    sentence_count: sentences.length,
   639→    avg_sentence_length: avgSentenceLength,
   640→    communication_score: communicationScore,
   641→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   642→  };
   643→}
   644→
   645→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   646→  const tips = [];
   647→
   648→  if (fillerRate > 3) {
   649→    const topFillers = Object.entries(fillerCounts)
   650→      .sort((a, b) => b[1] - a[1])
   651→      .slice(0, 3)
   652→      .map(([word, count]) => `"${word}" (${count}x)`);
   653→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   654→  }
   655→
   656→  if (wpm > 160) {
   657→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   658→  } else if (wpm < 110) {
   659→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   660→  }
   661→
   662→  if (wordCount < 80) {
   663→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   664→  }
   665→
   666→  if (tips.length === 0) {
   667→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   668→  }
   669→
   670→  return tips;
   671→}
