   996→// ─── TTS: Now with automatic fallback + database caching ─────
   997→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
   998→async function textToSpeech(text, options = {}) {
   999→  const pool = require('./db');
  1000→  const crypto = require('crypto');
  1001→
  1002→  try {
  1003→    const voice = options.voice || 'nova';
  1004→    const speed = options.speed || 1.0;
  1005→
  1006→    // Truncate text to ~4000 chars (TTS API limit is 4096)
  1007→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1008→
  1009→    // Generate cache key from text + voice
  1010→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1011→
  1012→    // Check cache first — serves audio even when daily token limit is exhausted
  1013→    try {
  1014→      const cached = await pool.query(
  1015→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1016→        [cacheKey]
  1017→      );
  1018→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1019→        const buf = Buffer.from(cached.rows[0].audio_data);
  1020→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1021→        return buf;
  1022→      }
  1023→    } catch (cacheErr) {
  1024→      // Cache miss or table doesn't exist yet — continue to API
  1025→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1026→    }
  1027→
  1028→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1029→
  1030→    // Use provider service with automatic fallback
  1031→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1032→      voice,
  1033→      speed,
  1034→      subscriptionId: options.subscriptionId,
  1035→    });
  1036→
  1037→    if (!buf) {
  1038→      console.log('[tts] All providers failed, returning null for browser fallback');
  1039→      return null;
  1040→    }
  1041→
  1042→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1043→
  1044→    // Cache the audio for future use (non-blocking)
  1045→    if (buf.length > 100) {
  1046→      pool.query(
  1047→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1048→         VALUES ($1, $2, $3, $4)
  1049→         ON CONFLICT (text_hash) DO NOTHING`,
  1050→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1051→      ).then(() => {
  1052→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1053→      }).catch(err => {
  1054→        // Non-fatal — caching failure doesn't break TTS
  1055→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1056→      });
  1057→    }
  1058→
  1059→    return buf;
  1060→  } catch (err) {
